import{_ as t,o as a,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Configuration des canaux d’upload","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/upload/index.md","filePath":"fr-FR/upload/index.md","lastUpdated":1781962217000}'),i={name:"fr-FR/upload/index.md"};function s(n,e,o,l,u,c){return a(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="configuration-des-canaux-d-upload" tabindex="-1">Configuration des canaux d’upload <a class="header-anchor" href="#configuration-des-canaux-d-upload" aria-label="Permalink to &quot;Configuration des canaux d’upload&quot;">​</a></h1><p>Dans ImgBed, chaque destination de stockage est configurée comme un canal. Vous choisissez où enregistrer les images, vidéos, audios et autres fichiers dans les paramètres d’upload.</p><h2 id="ou-configurer" tabindex="-1">Où configurer <a class="header-anchor" href="#ou-configurer" aria-label="Permalink to &quot;Où configurer&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Paramètres système -&gt; Paramètres d’upload</span></span></code></pre></div><p>Vous pouvez y ajouter des canaux, les activer ou désactiver, définir des limites de capacité, ajouter des notes et tester les connexions.</p><h2 id="canaux-disponibles" tabindex="-1">Canaux disponibles <a class="header-anchor" href="#canaux-disponibles" aria-label="Permalink to &quot;Canaux disponibles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Canal</th><th>Usage principal</th></tr></thead><tbody><tr><td>Cloudflare R2</td><td>Stockage objet chez Cloudflare</td></tr><tr><td>S3</td><td>AWS S3, Backblaze B2, MinIO et services compatibles</td></tr><tr><td>Google Drive</td><td>Enregistrer dans Google Drive</td></tr><tr><td>OneDrive</td><td>Enregistrer dans Microsoft OneDrive</td></tr><tr><td>Dropbox</td><td>Enregistrer dans Dropbox</td></tr><tr><td>pCloud</td><td>Enregistrer dans pCloud</td></tr><tr><td>WebDAV</td><td>NAS, disques cloud ou services compatibles WebDAV</td></tr><tr><td>Telegram</td><td>Utiliser un canal Telegram comme destination</td></tr><tr><td>Discord</td><td>Utiliser un canal Discord comme destination</td></tr><tr><td>GitHub Releases</td><td>Enregistrer dans les Release Assets de GitHub</td></tr><tr><td>GitLab Packages</td><td>Enregistrer dans le Generic Package Registry de GitLab</td></tr><tr><td>Hugging Face</td><td>Enregistrer dans un dépôt Hugging Face</td></tr><tr><td>Yandex</td><td>Enregistrer dans Yandex Disk</td></tr></tbody></table><h2 id="avant-d-ajouter-un-canal" tabindex="-1">Avant d’ajouter un canal <a class="header-anchor" href="#avant-d-ajouter-un-canal" aria-label="Permalink to &quot;Avant d’ajouter un canal&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Point</th><th>À vérifier</th></tr></thead><tbody><tr><td>Compte de stockage</td><td>Le compte où les fichiers seront réellement enregistrés</td></tr><tr><td>API Key / Token</td><td>Les identifiants requis par le canal</td></tr><tr><td>Dossier de stockage</td><td>Souvent <code>imgbed</code>, sauf si vous voulez une autre organisation</td></tr><tr><td>Limite de capacité</td><td>Si le canal doit cesser de recevoir des fichiers à partir d’un seuil</td></tr><tr><td>Domaine public</td><td>Si vous utilisez un CDN ou un domaine personnalisé</td></tr></tbody></table><h2 id="apres-enregistrement" tabindex="-1">Après enregistrement <a class="header-anchor" href="#apres-enregistrement" aria-label="Permalink to &quot;Après enregistrement&quot;">​</a></h2><ol><li>Vérifiez que la carte du canal apparaît.</li><li>Vérifiez que le canal est activé.</li><li>Contrôlez que les identifiants et le dossier sont bien enregistrés.</li><li>Lancez une consultation de capacité si le canal le permet.</li><li>Envoyez une image de test et ouvrez le lien renvoyé.</li></ol><p>En cas d’échec, vérifiez d’abord les identifiants, permissions, dossier de destination et limites de l’API du fournisseur.</p>',12)])])}const h=t(i,[["render",s]]);export{g as __pageData,h as default};
